import os
import pickle
import shutil
from datetime import timedelta

class Cache:
    def __init__(self, cache_dir="cache", expiration=timedelta(days=7)):
        self.cache_dir = cache_dir
        if not os.path.exists(self.cache_dir):
            os.makedirs(self.cache_dir)
        self.expiration = expiration

    def _key(self, key):
        return f"{self.cache_dir}/{key}"

    def set(self, key, value):
        cache_path = self._key(key)
        with open(cache_path, "wb") as f:
            pickle.dump((value, self.expiration), f)
        print(f"Stored {key} in the cache.")

    def get(self, key, default=None):
        cache_path = self._key(key)
        if os.path.exists(cache_path):
            with open(cache_path, "rb") as f:
                cached_value, expiration = pickle.load(f)
                if timedelta(seconds=int(time.time())) < expiration:
                    return cached_value
        return default

    def clear(self, key=None):
        if key is None:
            for file in os.listdir(self.cache_dir):
                shutil.rmtree(os.path.join(self.cache_dir, file))
        else:
            cache_path = self._key(key)
            if os.path.exists(cache_path):
                os.remove(cache_path)
                print(f"Cleared {key} from the cache.")